package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertThrows;

import java.io.InvalidObjectException;
import java.io.ObjectInputStream;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

public class LazilyParsedNumberTest {

  private LazilyParsedNumber lazilyParsedNumber;

  @BeforeEach
  public void setUp() {
    lazilyParsedNumber = new LazilyParsedNumber("123.45");
  }

  @Test
  public void testReadObject_throwsInvalidObjectException() throws Exception {
    ObjectInputStream mockIn = Mockito.mock(ObjectInputStream.class);

    Method readObjectMethod = LazilyParsedNumber.class.getDeclaredMethod("readObject", ObjectInputStream.class);
    readObjectMethod.setAccessible(true);

    InvalidObjectException thrown = assertThrows(InvalidObjectException.class, () -> {
      readObjectMethod.invoke(lazilyParsedNumber, mockIn);
    });

    assertEquals("Deserialization is unsupported", thrown.getCause().getMessage());
  }
}
